arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now sets the UTF-8 EFS flag for
        // non-ASCII entry names. The legacy Java consumer expects Shift-JIS,
        // so pass the encoding explicitly to keep entries readable.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices("cache")] no longer falls
// back to non-keyed registrations. Register with the matching key.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

